// ─── WEEK GENERATION (full 2026) ──────────────────────────────────────────────
function generateWeeks() {
  const weeks = [];
  let d = new Date("2026-04-13T00:00:00"); // Start from April 13
  const end = new Date("2026-12-28T00:00:00");
  while (d <= end) {
    const s = new Date(d);
    const e2 = new Date(d); e2.setDate(d.getDate()+6);
    weeks.push({
      label: `${s.toLocaleDateString("en-US",{month:"short",day:"numeric"})}–${e2.toLocaleDateString("en-US",{month:"short",day:"numeric"})}`,
      start: s.toISOString().slice(0,10),
      month: s.getMonth(),
    });
    d.setDate(d.getDate()+7);
  }
  return weeks;
}
const WEEKS = generateWeeks();

function getWeekDates(startStr) {
  const d = new Date(startStr+"T00:00:00");
  return Array.from({length:7},(_,i)=>{ const x=new Date(d); x.setDate(d.getDate()+i); return x; });
}
function dk(date) { return date.toISOString().slice(0,10); }
function bk(wid, dateStr, sh) { return `${wid}__${dateStr}__${sh}`; }

