// ─── HELPERS ──────────────────────────────────────────────────────────────────
function isNightVal(val){ return val && /\b([89]pm|10pm|night|HOT CUT|hop|splicer)/i.test(val); }
function isOffVal(val){ return val==="OFF"||val==="n/a"; }

// Splits "9AM: some job text" into bold time + normal text, always uppercase AM/PM
function formatJobText(val){
  if(!val) return val;
  const normalized = val.replace(/\b(\d{1,2}(?::\d{2})?)\s*(am|pm)\b/gi, (_, t, ap) => `${t}${ap.toUpperCase()}`);
  const match = normalized.match(/^(\d{1,2}(?::\d{2})?\s*(?:AM|PM)?:?\s*)/);
  if(match){
    const time = match[1];
    const rest = normalized.slice(time.length);
    return <><strong>{time}</strong>{rest}</>;
  }
  return normalized;
}

function Overlay({children,onClick}){
  return <div onClick={onClick} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:300,padding:16}}>{children}</div>;
}
function FF({label,children}){
  return <div><div style={{fontSize:8,letterSpacing:2,color:"#374151",marginBottom:4,fontWeight:700}}>{label}</div>{children}</div>;
}

// ─── VACATION CALENDAR PICKER ─────────────────────────────────────────────────
function VacPicker({worker,vacSet,sickSet,onToggleVac,onToggleSick,onBack}){
  const [mon,setMon]=useState(new Date().getMonth());
  const [yr,setYr]=useState(2026);
  const first=new Date(yr,mon,1);
  const daysInMonth=new Date(yr,mon+1,0).getDate();
  const startDow=(first.getDay()+6)%7;
  const cells=[];
  for(let i=0;i<startDow;i++) cells.push(null);
  for(let d=1;d<=daysInMonth;d++) cells.push(d);
  const toDs=(d)=>`${yr}-${String(mon+1).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
  return(
    <div>
      <button onClick={onBack} style={{fontSize:10,color:"#1F2937",background:"none",border:"none",cursor:"pointer",marginBottom:10,fontFamily:"inherit"}}>← Back</button>
      <div style={{fontWeight:700,fontSize:13,color:worker.color,marginBottom:10}}>{worker.name}</div>
      <div style={{display:"flex",gap:6,marginBottom:12,flexWrap:"wrap"}}>
        <span style={{fontSize:10,color:"#15803D",background:"#DCFCE7",padding:"2px 8px",borderRadius:4}}>🟢 = Vacation</span>
        <span style={{fontSize:10,color:"#854D0E",background:"#FEF9C3",padding:"2px 8px",borderRadius:4}}>🟡 = Sick / Time Off</span>
      </div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:10}}>
        <button onClick={()=>{if(mon===0){setMon(11);setYr(y=>y-1);}else setMon(m=>m-1);}} style={navB}>◀</button>
        <span style={{fontSize:12,fontWeight:700,color:"#1C1917"}}>{MONTHS_LABEL[mon]} {yr}</span>
        <button onClick={()=>{if(mon===11){setMon(0);setYr(y=>y+1);}else setMon(m=>m+1);}} style={navB}>▶</button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,textAlign:"center"}}>
        {["Mo","Tu","We","Th","Fr","Sa","Su"].map(d=><div key={d} style={{fontSize:9,color:"#57534E",paddingBottom:3,fontWeight:600}}>{d}</div>)}
        {cells.map((d,i)=>{
          if(!d) return <div key={i}/>;
          const ds=toDs(d);
          const isVac=vacSet.includes(ds), isSick=sickSet.includes(ds);
          const isPast=new Date(ds+"T00:00:00")<new Date(new Date().toDateString());
          const handleClick=()=>{
            if(isPast) return;
            if(!isVac&&!isSick){onToggleVac(ds);}
            else if(isVac){onToggleVac(ds);onToggleSick(ds);}
            else{onToggleSick(ds);}
          };
          return(
            <div key={i} onClick={handleClick} style={{
              padding:"5px 2px",borderRadius:4,fontSize:11,cursor:isPast?"default":"pointer",
              background:isVac?"#BBF7D0":isSick?"#FEF08A":isPast?"#F5F3EE":"#fff",
              border:`1px solid ${isVac?"#86EFAC":isSick?"#FDE047":isPast?"#EDE9E1":"#DDD8CF"}`,
              color:isVac?"#15803D":isSick?"#854D0E":isPast?"#C8C2B5":"#1C1917",
              fontWeight:isVac||isSick?700:400,
            }}>{d}</div>
          );
        })}
      </div>
      <div style={{marginTop:10,fontSize:10,color:"#57534E"}}>
        {vacSet.size} vacation · {sickSet.size} sick/off days
      </div>
    </div>
  );
}

