const MH={display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,fontSize:11,fontWeight:700,color:"#1F2937",letterSpacing:2,borderBottom:"2px solid #CCFBF1",paddingBottom:10};
const CB={background:"none",border:"none",color:"#9E9589",cursor:"pointer",fontSize:16};
const SEL_STATIC={width:"100%",padding:"7px 10px",background:"#F5F3EE",color:"#1C1917",border:"1px solid #CBD5E1",borderRadius:5,fontSize:11,fontFamily:"'Segoe UI','Helvetica Neue',Arial,sans-serif",outline:"none"};
