// ─── HELPERS ──────────────────────────────────────────────────────────────────

/** Save the entire schedule object to Firebase */
export function saveSchedule(schedule) {
  return set(ref(db, "schedule"), schedule);
}

/** Save vacations */
export function saveVacations(vacations) {
  return set(ref(db, "vacations"), vacations);
}

/** Save sick days */
export function saveSickDays(sickDays) {
  return set(ref(db, "sickDays"), sickDays);
}

/** Save on-call status */
export function saveOnCall(onCall) {
  return set(ref(db, "onCall"), onCall);
}

/** Save extra workers added by managers */
export function saveExtraWorkers(workers) {
  return set(ref(db, "extraWorkers"), workers);
}

/** Listen for live changes to all schedule data */
export function subscribeToData(callback) {
  const r = ref(db, "/");
  return onValue(r, (snapshot) => {
    const data = snapshot.val() || {};
    callback(data);
  });
}
